import cv2import osimport csvimport randomfrom scipy import ndimageimport numpy as npfrom PIL import Imageimport mathWINDOW_NAME = 'sample image'def close_windows():    cv2.destroyAllWindows()    cv2.waitKey(1)def intify_tuple(tup):    return tuple(map(lambda x: int(x), tup))def add_tuple(at, bt):    ret = ()    for a, b in zip(at, bt):        ret = ret + (a + b,)    return retdef add_alpha(img):    alpha = np.ones(img.shape[:-1] + (1,), dtype=np.uint8) * 255    img = np.concatenate((img, alpha), axis=-1)    return imgdef image_scale(img, shape=None, factor=1.05):    h, w, _ = img.shape    if shape is None:        return cv2.resize(img, (int(w * factor), int(h * factor))), None    else:        assert len(shape) == 2        return cv2.resize(img, shape), shape[1] / wdef cv_imshow(img):    cv2.imshow(WINDOW_NAME, img)    while True:        key = cv2.waitKey(10)        if key & 0xFF == ord('q'):            break    close_windows()def pil_to_np(img):    ret = np.array(img.getdata(), dtype=np.uint8).reshape(img.size[0], img.size[1], 4)    return retdef blend(a, b):    a = Image.fromarray(a)    b = Image.fromarray(b)    ret = Image.alpha_composite(b, a)    ret = pil_to_np(ret)[:, :, :3]    ret = np.ascontiguousarray(ret, dtype=np.uint8)    return retdef show_img(img):    img = Image.fromarray(img)    img.show()def org_corners(width, height, center, angle):    tl = (0, 0)    tr = add_tuple(tl, (width, 0))    br = add_tuple(tl, (width, height))    bl = add_tuple(tl, (0, height))    theta = -angle    c, s = np.cos(theta), np.sin(theta)    r = np.array(((c, -s), (s, c)))    return [tl, tr, bl, br], new_corners([tl, tr, bl, br], r, width, height, center)def new_corners(corners_og, R, icw, ich, ic_center):    corner_mat = np.reshape(np.array(corners_og), (-1, 2))    corner_mat = corner_mat - np.array([icw / 2, ich / 2])    corner_mat = R.dot(corner_mat.T)    corner_mat = corner_mat.T + ic_center    corner_mat = corner_mat.astype("uint32")    corner_list = [tuple(x) for x in corner_mat]    return corner_listdef get_layer(png, shape=(256, 256), factor=None):    layer = cv2.imread(png)    layer, rescale_factor = image_scale(layer, shape=shape, factor=factor)    h, w, _ = layer.shape    layer = add_alpha(layer)    return h, w, rescale_factor, layerdef img_generator(alpha, delta_weight):    angle_degree = np.random.uniform(-alpha, alpha)    angle_radian = math.radians(angle_degree)    back_height, back_width, rescale_factor, backlayer = get_layer('U26_backlayer.png', shape=(256, 256))    ic_height, ic_width, _, frontlayer = get_layer('U26_ic.png', shape=None, factor=rescale_factor)    frontlayer = ndimage.rotate(frontlayer, angle_degree, reshape=True)    front_height, front_width, _ = frontlayer.shape    width_delta = int((back_width - front_width) / 2)    height_delta = int((back_height - front_height) / 2)    cdx = random.randint(int(-width_delta * delta_weight), int(width_delta * delta_weight))    cdy = random.randint(int(-height_delta * delta_weight), int(height_delta * delta_weight))    ic_center = np.array([back_width / 2 + cdx, back_height / 2 + cdy])    frontlayer = cv2.copyMakeBorder(frontlayer, height_delta + cdy, height_delta - cdy, width_delta + cdx,                                    width_delta - cdx, cv2.BORDER_CONSTANT,                                    value=(0, 0, 0, 0))    frontlayer = cv2.resize(frontlayer, (back_width, back_height))    img = blend(frontlayer, backlayer)    og_corners, corners = org_corners(ic_width, ic_height, ic_center, angle_radian)    #for corner in corners:        #png = cv2.circle(img, corner, 10, (0, 0, 255), 10)    #png = cv2.circle(img, tuple(np.ndarray.astype(ic_center, dtype=int)), 10, (255, 0, 0), 10)    #cv_imshow(png)    return img, ic_center, corners, angle_degreedef generate_dataset(size, angle, delta):    directory_img = "/home/kerem/TOKEN_AI_PROJECT/Docker/Model_Attempt/Dataset/Images_Ref_Points_Test"    directory_labels = "/home/kerem/TOKEN_AI_PROJECT/Docker/Model_Attempt/Dataset/"    pwd = os.getcwd()    _, center_org, ref_points, _ = img_generator(0, 0)    os.chdir(directory_labels)    f = open('labels_ref_points_test.csv', 'w')    writer = csv.writer(f)    writer.writerow([ref_points, tuple(center_org.astype(int))])    print("Reference points written...")    for i in range(size):        os.chdir(pwd)        img, ic_center, corners, beta = img_generator(angle, delta)        os.chdir(directory_img)        #delta_center = ic_center.astype(int) - center_org.astype(int)        filename = "U26_{idx}.png".format(idx=i)        cv2.imwrite(filename, img)        os.chdir(directory_labels)        writer.writerow(corners)        print(i)    f.close()#img_generator(0, 0)generate_dataset(2000, 10, 0.1)